+
+    return result[0]?.value ?? null;
+  }
+
+  async setPreference(key: string, value: string): Promise<void> {
+    // Note: This requires writable DB - may fail in readonly mode
+    await this.db
+      .insert(preferences)
+      .values({ key, value })
+      .onConflictDoUpdate({
+        target: preferences.key,
+        set: { value },
+      });
+  }
+
+  async close(): Promise<void> {
+    this.sqlite.close();
+    this.cache.clear();
+    this.phageList = null;
+  }
+}

